  // ============================================================
  // Group 14: DiscriminatorComputer Integration
  // ============================================================
  group('14. DiscriminatorComputer integration', () {
    test('isExplicit for Quasar short discriminators', () {
      expect(DiscriminatorComputer.isExplicit([0]), isTrue);
      expect(DiscriminatorComputer.isExplicit([1]), isTrue);
      expect(DiscriminatorComputer.isExplicit([1, 2]), isTrue);
      expect(DiscriminatorComputer.isExplicit([0, 1, 2, 3]), isTrue);
      // 8-byte discriminator should NOT be explicit (that's Anchor)
      expect(
          DiscriminatorComputer.isExplicit([0, 1, 2, 3, 4, 5, 6, 7]), isFalse);
      print('  1-4 byte discs are explicit, 8-byte is not');
    });

    test('fromExplicit creates correct Uint8List', () {
      final disc = DiscriminatorComputer.fromExplicit([42]);
      expect(disc, isA<Uint8List>());
      expect(disc.length, 1);
      expect(disc[0], 42);

      final multi = DiscriminatorComputer.fromExplicit([1, 2]);
      expect(multi.length, 2);
      expect(multi[0], 1);
      expect(multi[1], 2);
    });

    test('compareDiscriminators: same length match', () {
      expect(
        DiscriminatorComputer.compareDiscriminators(
            Uint8List.fromList([0]), Uint8List.fromList([0])),
        isTrue,
      );
      expect(
        DiscriminatorComputer.compareDiscriminators(
            Uint8List.fromList([1, 2]), Uint8List.fromList([1, 2])),
        isTrue,
      );
    });

    test('compareDiscriminators: different length mismatch', () {
      expect(
        DiscriminatorComputer.compareDiscriminators(
            Uint8List.fromList([0]), Uint8List.fromList([0, 1])),
        isFalse,
      );
    });

    test('compareDiscriminators: same length content mismatch', () {
      expect(
        DiscriminatorComputer.compareDiscriminators(
            Uint8List.fromList([0]), Uint8List.fromList([1])),
        isFalse,
      );
    });

    test('resolve() with explicit list returns it directly', () {
      final resolved = DiscriminatorComputer.resolve(
        prefix: 'global',
        name: 'deposit',
        explicit: [42],
      );
      expect(resolved, [42]);
      expect(resolved.length, 1);
    });

    test('resolve() without explicit falls back to SHA256', () {
      final resolved = DiscriminatorComputer.resolve(
        prefix: 'global',
        name: 'deposit',
        explicit: null,
      );
      expect(resolved.length, 8, reason: 'SHA256 discriminator is 8 bytes');
    });
  });

