  // ============================================================
  // Group 16: Zero-Copy Account Encoding / Decoding
  // ============================================================
  group('16. Zero-copy encoding/decoding', () {
    test('Escrow round-trip: encode → decode', () async {
      final r = _load('quasar_escrow.idl.json');
      final coder = ZeroCopyAccountsCoder(r.idl);

      // Build a fake Escrow account data
      final maker = List.filled(32, 0x01);
      final mintA = List.filled(32, 0x02);
      final mintB = List.filled(32, 0x03);
      final makerTaB = List.filled(32, 0x04);

      final escrowData = <String, dynamic>{
        'maker': Uint8List.fromList(maker),
        'mintA': Uint8List.fromList(mintA),
        'mintB': Uint8List.fromList(mintB),
        'makerTaB': Uint8List.fromList(makerTaB),
        'receive': BigInt.from(1000000),
        'bump': 254,
      };

      final encoded = await coder.encode('Escrow', escrowData);
      print('  encoded length: ${encoded.length}');

      // Discriminator [1] + 32*4 + 8 + 1 = 1 + 128 + 8 + 1 = 138
      expect(encoded.length, 138);
      // First byte should be discriminator [1]
      expect(encoded[0], 1);

      final decoded = coder.decode('Escrow', encoded);
      expect(decoded['receive'], BigInt.from(1000000));
      expect(decoded['bump'], 254);
      print('  decoded receive=${decoded['receive']} bump=${decoded['bump']}');

      // Verify pubkeys round-trip
      expect(
        (decoded['maker'] as Uint8List).toList(),
        maker,
      );
    });

    test('SimpleAccount round-trip: pubkey + u64 + u8', () async {
      final r = _load('quasar_test_misc.idl.json');
      final coder = ZeroCopyAccountsCoder(r.idl);

      final data = <String, dynamic>{
        'authority': Uint8List.fromList(List.filled(32, 0xAA)),
        'value': BigInt.from(42),
        'bump': 255,
      };

      final encoded = await coder.encode('SimpleAccount', data);
      // disc [1] + 32 + 8 + 1 = 42
      expect(encoded.length, 42);
      expect(encoded[0], 1);

      final decoded = coder.decode('SimpleAccount', encoded);
      expect(decoded['value'], BigInt.from(42));
      expect(decoded['bump'], 255);
      print('  SimpleAccount round-trip OK');
    });

    test('MultiDiscAccount: 2-byte discriminator', () async {
      final r = _load('quasar_test_misc.idl.json');
      final coder = ZeroCopyAccountsCoder(r.idl);

      final data = <String, dynamic>{
        'data': BigInt.from(99),
      };

      final encoded = await coder.encode('MultiDiscAccount', data);
      // disc [1,2] + 8 = 10
      expect(encoded.length, 10);
      expect(encoded[0], 1);
      expect(encoded[1], 2);

      final decoded = coder.decode('MultiDiscAccount', encoded);
      expect(decoded['data'], BigInt.from(99));
      print('  MultiDiscAccount 2-byte disc round-trip OK');
    });

    test('MultisigConfig: dynString + dynVec round-trip', () async {
      final r = _load('quasar_multisig.idl.json');
      final coder = ZeroCopyAccountsCoder(r.idl);

      final signer1 = Uint8List.fromList(List.filled(32, 0x11));
      final signer2 = Uint8List.fromList(List.filled(32, 0x22));

      final data = <String, dynamic>{
        'creator': Uint8List.fromList(List.filled(32, 0xFF)),
        'threshold': 2,
        'bump': 253,
        'label': 'test-ms',
        'signers': [signer1, signer2],
      };

      final encoded = await coder.encode('MultisigConfig', data);
      print('  MultisigConfig encoded length: ${encoded.length}');

      // disc [1] + pubkey(32) + u8 + u8 + dynString(4+7) + dynVec(4+32*2)
      // = 1 + 32 + 1 + 1 + 11 + 68 = 114
      expect(encoded.length, 114);
      expect(encoded[0], 1); // disc

      final decoded = coder.decode('MultisigConfig', encoded);
      expect(decoded['threshold'], 2);
      expect(decoded['bump'], 253);
      expect(decoded['label'], 'test-ms');
      final decodedSigners = decoded['signers'] as List;
      expect(decodedSigners.length, 2);
      expect((decodedSigners[0] as Uint8List).toList(), signer1.toList());
      print('  MultisigConfig round-trip OK');
    });
  });

