      expect(encoded[0], 10);
      print('  assignTest encoded length=${encoded.length}');
    });

    test('instruction decode round-trip', () {
      final r = _load('quasar_vault.idl.json');
      final coder = BorshInstructionCoder(r.idl);

      final encoded = coder.encode('deposit', {'amount': BigInt.from(7777)});
      final decoded = coder.decode(encoded);
      expect(decoded, isNotNull);
      expect(decoded!.name, 'deposit');
      // BorshInstructionCoder may return int or BigInt depending on size
      final amountValue = decoded.data['amount'];
      expect(
        amountValue == BigInt.from(7777) || amountValue == 7777,
        isTrue,
        reason: 'amount should be 7777 (got $amountValue, type=${amountValue.runtimeType})',
      );
      print('  deposit decode: name=${decoded.name} amount=$amountValue (${amountValue.runtimeType})');
    });
  });

