  // Group 18: IDL JSON Round-Trip (fromJson → toJson → fromJson)
  // ============================================================
  group('18. IDL JSON round-trip', () {
    final fixtures = [
      'quasar_vault.idl.json',
      'quasar_escrow.idl.json',
