        final r = _load(f);

        // Serialize back to JSON
        final reJson = r.idl.toJson();

        // Re-parse
        final idl2 = Idl.fromJson(reJson);

        // Structural equality checks
        expect(idl2.instructions.length, r.idl.instructions.length);
        expect(
            (idl2.accounts ?? []).length, (r.idl.accounts ?? []).length);
        expect((idl2.events ?? []).length, (r.idl.events ?? []).length);
        expect((idl2.types ?? []).length, (r.idl.types ?? []).length);
        expect((idl2.errors ?? []).length, (r.idl.errors ?? []).length);

        // Verify instruction names preserved
        for (var i = 0; i < r.idl.instructions.length; i++) {
          expect(idl2.instructions[i].name, r.idl.instructions[i].name);
          expect(idl2.instructions[i].discriminator,
              r.idl.instructions[i].discriminator);
        }

        // Verify format is still Quasar
        expect(idl2.format, IdlFormat.quasar);
        print('  $f round-trip OK');
      });
    }
  });

